import React, { useState, useEffect } from 'react';

import { getStats } from '../services/api';

function LiveStats() {

  const [stats, setStats] = useState({});

  useEffect(() => {

    const fetchStats = async () => {

      try {

        const response = await getStats();

        setStats(response.data);

      } catch (error) {

        console.error('Error fetching stats:', error);

      }

    };

    fetchStats();

    const interval = setInterval(fetchStats, 5000);

    return () => clearInterval(interval);

  }, []);

  return (
    <div className="stats-card">
      <h2 style={{ marginTop: 0, marginBottom: '20px', color: '#fff' }}>Live Stats</h2>
      <div className="stat-item">
        <span className="stat-label">CO₂ Emissions</span>
        <span className="stat-value neon-green">{stats.co2 || 'Loading...'}</span>
      </div>
      <div className="stat-item">
        <span className="stat-label">Energy Usage</span>
        <span className="stat-value neon-blue">{stats.energy || 'Loading...'}</span>
      </div>
    </div>
  );
}

export default LiveStats;
